import type { ComponentPropsWithoutRef } from 'react';
import clsx from 'clsx';
import styles from './Table.module.css';

function TableContainer({ className, ...props }: ComponentPropsWithoutRef<'div'>) {
  return (
    <div data-slot="table-container" className={clsx(styles.container, className)} {...props} />
  );
}

function Table({ className, ...props }: ComponentPropsWithoutRef<'table'>) {
  return <table data-slot="table" className={clsx(styles.root, className)} {...props} />;
}

function TableHeader({ className, ...props }: ComponentPropsWithoutRef<'thead'>) {
  return <thead data-slot="table-header" className={clsx(styles.header, className)} {...props} />;
}

function TableBody({ className, ...props }: ComponentPropsWithoutRef<'tbody'>) {
  return <tbody data-slot="table-body" className={clsx(styles.body, className)} {...props} />;
}

function TableFooter({ className, ...props }: ComponentPropsWithoutRef<'tfoot'>) {
  return <tfoot data-slot="table-footer" className={clsx(styles.footer, className)} {...props} />;
}

function TableRow({ className, ...props }: ComponentPropsWithoutRef<'tr'>) {
  return <tr data-slot="table-row" className={clsx(styles.row, className)} {...props} />;
}

function TableHead({
  className,
  numeric = false,
  ...props
}: ComponentPropsWithoutRef<'th'> & {
  numeric?: boolean;
}) {
  return (
    <th
      data-numeric={numeric || undefined}
      data-slot="table-head"
      className={clsx(styles.head, numeric && styles.numeric, className)}
      {...props}
    />
  );
}

function TableCell({
  className,
  numeric = false,
  ...props
}: ComponentPropsWithoutRef<'td'> & {
  numeric?: boolean;
}) {
  return (
    <td
      data-numeric={numeric || undefined}
      data-slot="table-cell"
      className={clsx(styles.cell, numeric && styles.numeric, className)}
      {...props}
    />
  );
}

function TableEmpty({
  children = 'No results.',
  className,
  colSpan,
  ...props
}: ComponentPropsWithoutRef<'td'> & {
  colSpan: number;
}) {
  return (
    <tr data-slot="table-row" className={clsx(styles.row, styles.emptyRow)}>
      <td
        data-slot="table-empty"
        colSpan={colSpan}
        className={clsx(styles.cell, styles.empty, className)}
        {...props}
      >
        {children}
      </td>
    </tr>
  );
}

function TableCaption({
  className,
  side = 'bottom',
  ...props
}: ComponentPropsWithoutRef<'caption'> & {
  side?: 'top' | 'bottom';
}) {
  return (
    <caption
      data-side={side}
      data-slot="table-caption"
      className={clsx(styles.caption, className)}
      {...props}
    />
  );
}

export {
  Table,
  TableBody,
  TableCaption,
  TableCell,
  TableContainer,
  TableEmpty,
  TableFooter,
  TableHead,
  TableHeader,
  TableRow,
};

@layer ui.components {
  .container {
    box-sizing: border-box;
    width: 100%;
    min-width: 0;
    overflow-x: auto;
    border: var(--table-container-border-width, var(--table-border-width, var(--border-width-sm)))
      solid var(--table-container-border-color, var(--table-border-color, var(--color-border)));
    border-radius: var(--table-container-radius, var(--radius-lg));
    background-color: var(--table-container-bg, var(--color-card));
    box-shadow: var(--table-container-shadow, none);
  }

  .root {
    --table-cell-padding-y-default: var(--table-cell-padding-y, var(--spacing-3));
    --table-empty-padding-y-default: calc(var(--table-cell-padding-y-default) * 2);

    box-sizing: border-box;
    width: 100%;
    border-collapse: collapse;
    border-spacing: 0;
    color: var(--table-color, var(--color-foreground));
    font-family: var(--table-font-family, var(--font-sans));
    font-size: var(--table-font-size, var(--text-sm));
    line-height: var(--table-line-height, var(--line-height-text-sm));
    text-align: left;
  }

  .caption {
    box-sizing: border-box;
    color: var(--table-caption-color, var(--color-muted-foreground));
    font-size: var(--table-caption-font-size, var(--text-sm));
    line-height: var(--table-caption-line-height, var(--line-height-text-sm));
    padding-inline: var(--table-caption-padding-x, var(--table-cell-padding-x, var(--spacing-4)));
    text-align: left;
    text-wrap: pretty;
  }

  .caption[data-side='top'] {
    caption-side: top;
    padding-block: var(--table-caption-padding-edge, var(--spacing-2))
      var(--table-caption-padding-y, var(--spacing-3));
  }

  .caption[data-side='bottom'] {
    caption-side: bottom;
    padding-block: var(--table-caption-padding-y, var(--spacing-3))
      var(--table-caption-padding-edge, var(--spacing-2));
  }

  .row {
    transition: var(--table-row-transition, background-color var(--transition-default));
  }

  .header .row,
  .body .row {
    border-bottom: var(--table-border-width, var(--border-width-sm)) solid
      var(--table-border-color, var(--color-border));
  }

  .body .row:hover {
    background-color: var(--table-row-bg-hover, var(--color-muted));
  }

  .body .row:last-child {
    border-bottom: 0;
  }

  .footer {
    border-top: var(--table-border-width, var(--border-width-sm)) solid
      var(--table-border-color, var(--color-border));
    background-color: var(--table-footer-bg, var(--color-muted));
    color: var(--table-footer-color, var(--table-color, var(--color-foreground)));
    font-weight: var(--table-footer-font-weight, var(--weight-medium));
  }

  .head,
  .cell {
    padding-block: var(--table-cell-padding-y-default);
    padding-inline: var(--table-cell-padding-x, var(--spacing-4));
    vertical-align: middle;
  }

  .head {
    color: var(--table-head-color, var(--color-muted-foreground));
    font-weight: var(--table-head-font-weight, var(--weight-medium));
    text-align: inherit;
    white-space: nowrap;
  }

  .cell {
    color: inherit;
  }

  .numeric {
    text-align: right;
    white-space: nowrap;
    font-variant-numeric: tabular-nums;
  }

  .emptyRow:hover {
    background-color: transparent;
  }

  .empty {
    padding-block: var(--table-empty-padding-y, var(--table-empty-padding-y-default));
    color: var(--table-empty-color, var(--color-muted-foreground));
    text-align: center;
  }
}
